// Calculate 75/25 split per NOIZY protocol
const { gross_amount, currency } = $json.body;

const grossNum = parseFloat(gross_amount);
const artistPool = Math.round(grossNum * 0.75 * 100) / 100;
const platformPool = Math.round(grossNum * 0.25 * 100) / 100;

return [
  {
    json: {
      ...$json.body,
      gross: {
        amount: grossNum,
        currency: currency
      },
      splits: {
        rule: "75_25",
        artist_pool: {
          amount: artistPool,
          percent: 0.75
        },
        platform_pool: {
          amount: platformPool,
          percent: 0.25
        }
      }
    }
  }
];

// Apportion artist_pool among contributors based on share_of_artist_pool
const data = $json;
const artistPoolAmount = data.splits.artist_pool.amount;
const contributors = data.contributors || [];

const apportioned = contributors.map(c => ({
  contributor_id: c.contributor_id,
  display_name: c.display_name,
  role: c.role,
  share_of_artist_pool: c.share_of_artist_pool,
  amount: Math.round(artistPoolAmount * c.share_of_artist_pool * 100) / 100,
  payout_destination: c.payout_destination || null
}));

return [
  {
    json: {
      ...data,
      splits: {
        ...data.splits,
        contributors: apportioned
      }
    }
  }
];

// Build HybridReceipt75_25 JSON matching /schemas/HybridReceipt75_25.schema.json
const crypto = require('crypto');
const data = $json;

const receipt = {
  schema_version: "1.0.0",
  receipt_id: `rcpt-${crypto.randomUUID()}`,
  created_at: new Date().toISOString(),
  event: {
    event_type: data.event_type,
    event_ref: data.event_ref
  },
  gross: data.gross,
  splits: data.splits,
  attribution: {
    source_contributions: data.splits.contributors.map(c => ({
      contribution_id: `contrib-${crypto.randomUUID()}`,
      contributor_id: c.contributor_id,
      asset_ref: c.contributor_id,
      consent_token_ref: `pending`
    })),
    display_credit_line: data.splits.contributors.map(c => c.display_name).join(' + ')
  },
  proof_links: {
    artifact_id: data.event_ref,
    manifest_id: "pending"
  },
  status: {
    state: "issued"
  }
};

return [{ json: receipt }];
